oxy_webhelp_navlinks = {"postgresql-d27243e30830":{"topics":[{"title":"PostgreSQL protection key features","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> provides unified data management, automated global data         protection, backup and recovery options for PostgreSQL databases, and advanced security         features to protect critical data.<\/p>","href":"postgresql\/postgresql_protection_key_features.html","attributes":{"data-id":"postgresql_protection_key_features"},"menu":{"hasChildren":false},"tocID":"postgresql_protection_key_features-d27243e30843","topics":[]},{"title":"PostgreSQL protection prerequisites","shortdesc":"<p class=\"shortdesc\">Information about the specific prerequisites that <span class=\"ph\">RSC<\/span> requires for         protecting PostgreSQL clusters.<\/p>","href":"postgresql\/postgresql_protection_prereq.html","attributes":{"data-id":"postgresql_protection_prereq"},"menu":{"hasChildren":false},"tocID":"postgresql_protection_prereq-d27243e30856","topics":[]},{"title":"Adding a host for PostgreSQL","shortdesc":"<p class=\"shortdesc\">To establish a connection between the PostgreSQL cluster and <span class=\"ph\">RSC<\/span>, add         a host for performing backup and recovery operations.<\/p>","href":"postgresql\/adding_host_postgresql.html","attributes":{"data-id":"adding_host_postgresql"},"menu":{"hasChildren":false},"tocID":"adding_host_postgresql-d27243e30870","topics":[]},{"title":"Adding a PostgreSQL cluster","shortdesc":"<p class=\"shortdesc\">Add a PostgreSQL cluster to establish a connection with the Rubrik cluster with the         required configuration details.<\/p>","href":"postgresql\/adding_postgresql_cluster.html","attributes":{"data-id":"adding_postgresql_cluster"},"menu":{"hasChildren":false},"tocID":"adding_postgresql_cluster-d27243e30884","topics":[]},{"title":"Editing a PostgreSQL cluster","shortdesc":"<p class=\"shortdesc\">To modify a PostgreSQL cluster, edit the PostgreSQL cluster settings.<\/p>","href":"postgresql\/editing_postrgesql_cluster.html","attributes":{"data-id":"editing_postrgesql_cluster"},"menu":{"hasChildren":false},"tocID":"editing_postrgesql_cluster-d27243e30895","topics":[]},{"title":"Refreshing a PostgreSQL cluster","shortdesc":"<p class=\"shortdesc\">To ensure that the PostgreSQL cluster information is up to date, refresh the         PostgreSQL cluster.<\/p>","href":"postgresql\/refreshing_postgresql_cluster.html","attributes":{"data-id":"refreshing_postgresql_cluster"},"menu":{"hasChildren":false},"tocID":"refreshing_postgresql_cluster-d27243e30906","topics":[]},{"title":"Deleting a PostreSQL cluster","shortdesc":"<p class=\"shortdesc\">To remove a PostgreSQL cluster that is no longer required, delete the PostgreSQL         cluster from the Rubrik cluster.<\/p>","href":"postgresql\/deleting_postresql_cluster.html","attributes":{"data-id":"deleting_postresql_cluster"},"menu":{"hasChildren":false},"tocID":"deleting_postresql_cluster-d27243e30917","topics":[]},{"title":"Rubrik cloud cluster elastic storage for PostgreSQL","shortdesc":"<p class=\"shortdesc\">Rubrik Cloud Cluster Elastic Storage is a cloud-native Rubrik deployment model that         protects PostgreSQL workloads running on virtual instances within a Virtual Private Cloud in         public cloud environments.<\/p>","href":"postgresql\/postgresql_rbk_cloud_cluster_elastic_storage.html","attributes":{"data-id":"postgresql_rbk_cloud_cluster_elastic_storage"},"menu":{"hasChildren":false},"tocID":"postgresql_rbk_cloud_cluster_elastic_storage-d27243e30928","topics":[]},{"title":"User notes for PostgreSQL","shortdesc":"<p class=\"shortdesc\">You can add user notes to explain the reason behind performing a specific task,         ensuring comprehensive audit tracking for your PostgreSQL environment.<\/p>","href":"postgresql\/postgresql_user_notes.html","attributes":{"data-id":"postgresql_user_notes"},"menu":{"hasChildren":false},"tocID":"postgresql_user_notes-d27243e30939","topics":[]},{"title":"PostgreSQL cluster protection","shortdesc":"<p class=\"shortdesc\">PostgreSQL cluster protection uses SLA Domains to provide configurable data         protection policies, ensuring consistent and secure management of PostgreSQL cluster         workloads.<\/p>","href":"postgresql\/postgresql_cluster_protection.html","attributes":{"data-id":"postgresql_cluster_protection"},"menu":{"hasChildren":false},"tocID":"postgresql_cluster_protection-d27243e30950","next":"postgresql_cluster_protection-d27243e30950"},{"title":"Changing the retention policy of a PostgreSQL snapshot","shortdesc":"<p class=\"shortdesc\">To optimize data accessibility, change the retention policy of a PostgreSQL         snapshot.<\/p>","href":"postgresql\/changing_retention_policy_postgresql.html","attributes":{"data-id":"changing_retention_policy_postgresql"},"menu":{"hasChildren":false},"tocID":"changing_retention_policy_postgresql-d27243e30984","topics":[]},{"title":"Multiple archival locations for PostgreSQL","shortdesc":"<p class=\"shortdesc\">You can configure multiple archival policies within a single SLA Domain to automate         the delivery of snapshots and log data to distinct cloud storage targets.<\/p>","href":"postgresql\/multiple_archival_locations_postgresql.html","attributes":{"data-id":"multiple_archival_locations_postgresql"},"menu":{"hasChildren":false},"tocID":"multiple_archival_locations_postgresql-d27243e30995","topics":[]},{"title":"Creating restore mount point for a PostgreSQL cluster","shortdesc":"<p class=\"shortdesc\">To recover a PostgreSQL cluster, create a restore mount point by mounting a snapshot         of backup data to the mount point using NFS and then performing the recovery         instructions.<\/p>","href":"postgresql\/creating_restore_mp_postgresql.html","attributes":{"data-id":"creating_restore_mp_postgresql"},"menu":{"hasChildren":false},"tocID":"creating_restore_mp_postgresql-d27243e31006","topics":[]},{"title":"Unmounting restore mount point after PostgreSQL cluster recovery","shortdesc":"<p class=\"shortdesc\">After recovering a PostgreSQL cluster, unmount it to remove the metadata associated         with the selected PostgreSQL cluster.<\/p>","href":"postgresql\/unmouting_restore_mount_point_postgresql_cluster.html","attributes":{"data-id":"unmouting_restore_mount_point_postgresql_cluster"},"menu":{"hasChildren":false},"tocID":"unmouting_restore_mount_point_postgresql_cluster-d27243e31017","topics":[]},{"title":"Recovering a PostgreSQL cluster","shortdesc":"<p class=\"shortdesc\">After you have created a mount point for the PostgreSQL cluster, recover the cluster         manually by following the recovery instructions.<\/p>","href":"postgresql\/recovering_postgresql_cluster.html","attributes":{"data-id":"recovering_postgresql_cluster"},"menu":{"hasChildren":false},"tocID":"recovering_postgresql_cluster-d27243e31028","topics":[]},{"title":"High Availability for a PostgreSQL cluster","shortdesc":"<p class=\"shortdesc\">High Availability for a PostgreSQL cluster ensures uninterrupted system operation and         data protection against hardware and software failures, natural disasters, power outages,         and network failures.<\/p>","href":"postgresql\/ha_postgres_cluster.html","attributes":{"data-id":"ha_postgres_cluster"},"menu":{"hasChildren":false},"tocID":"ha_postgres_cluster-d27243e31039","topics":[]},{"title":"PostgreSQL automated recovery","shortdesc":"<p class=\"shortdesc\">PostgreSQL automated recovery enables you to recover PostgreSQL clusters on <span class=\"ph\">RSC<\/span> from Rubrik CDM versions 9.4.1 and later without requiring manual         steps.<\/p>","href":"postgresql\/postgresql_automated_recovery.html","attributes":{"data-id":"postgresql_automated_recovery"},"menu":{"hasChildren":false},"tocID":"postgresql_automated_recovery-d27243e31050","next":"postgresql_automated_recovery-d27243e31050"},{"title":"PostgreSQL protection limitations","shortdesc":"<p class=\"shortdesc\">PostgreSQL clusters are subject to certain protection limitations.<\/p>","href":"postgresql\/postgresql_protection_limitations.html","attributes":{"data-id":"postgresql_protection_limitations"},"menu":{"hasChildren":false},"tocID":"postgresql_protection_limitations-d27243e31086","topics":[]}]}};